async function deployMSFTPoseidon() {
    const [deployer] = await ethers.getSigners()
    const PoseidonHash = await ethers.getContractFactory("PoseidonU2bn256Hasher");
    const hash= await PoseidonHash.deploy();
    await hash.waitForDeployment();
    console.log("PoseidonHasher is deployed at ", hash.target);


    const Simple = await ethers.getContractFactory("SimplePoseidon", {
        signer: deployer[0],
        libraries: {
            PoseidonU2bn256Hasher:  hash.target,
        },
    });
    const simple= await Simple.deploy();
    await simple.waitForDeployment();
    console.log("SimplePoseidon is deployed at ", simple.target);
}
