function hashElgamal(elgamal) {
    // 使用 ethers 的 solidityPackedKeccak256 方法对 ElGamal 结构进行编码并计算哈希
    return ethers.solidityPackedKeccak256(
        ["uint256", "uint256", "uint256", "uint256"],
        [elgamal.cl_x, elgamal.cl_y, elgamal.cr_x, elgamal.cr_y]
    );
}
